solutions.javascript:
// Define a function to validate the exposed ports of a Docker container
function validateExposedPorts(container) {
  // Use Object.keys() to get an array of port numbers, then use every() to check if all ports are valid
  if (Object.keys(container.exposed_ports).every(port => port >= 1 && port <= 65535)) {
    return container; // If all ports are valid, return the container object
  } else {
    return 'Error: One or more ports are not valid.'; // If any port is not valid, return an error message
  }
}

