class Solution:
    def validateExposedPorts(self, container):
        # Use the `every()` method to check if all ports are valid
        if all(port >= 1 and port <= 65535 for port in container.exposed_ports.keys()):
            return container # If all ports are valid, return the container object
        else:
            return 'Error: One or more ports are not valid.' # If any port is not valid, return an error message
